mapper.sql:
t.tenant_id = #{tenantId}
AND t.del_flag = '0'

  AND (
    t.template_name LIKE CONCAT('%', #{query.keyword}, '%')
    OR t.template_code LIKE CONCAT('%', #{query.keyword}, '%')
    OR t.business_category LIKE CONCAT('%', #{query.keyword}, '%')
    OR t.domain_category LIKE CONCAT('%', #{query.keyword}, '%')
    OR t.template_tags LIKE CONCAT('%', #{query.keyword}, '%')
    OR t.description LIKE CONCAT('%', #{query.keyword}, '%')
  )


  AND t.template_name LIKE CONCAT('%', #{query.templateName}, '%')


  AND t.usage_scene = #{query.usageScene}


  AND t.business_category = #{query.businessCategory}


  AND t.domain_category = #{query.domainCategory}


  AND t.status = #{query.status}


  AND t.is_recommended = #{query.isRecommended}

mapper.select:
SELECT t.id, t.tenant_id, t.template_name, t.template_code, t.usage_scene, t.business_category, t.domain_category, t.template_tags, t.description, LEFT(t.prompt_content, 180) AS content_summary, t.example_input, t.status, t.is_recommended, t.sort_order, t.use_count, t.test_count, t.download_count, t.remark, t.create_by, cu.real_name AS creator_name, t.create_time, t.update_by, uu.real_name AS updater_name, t.update_time FROM ai_prompt_template t LEFT JOIN sys_user cu ON cu.tenant_id = t.tenant_id AND cu.id = t.create_by AND cu.del_flag = 0 LEFT JOIN sys_user uu ON uu.tenant_id = t.tenant_id AND uu.id = t.update_by AND uu.del_flag = 0
AND t.status = '0'
ORDER BY t.is_recommended DESC, t.sort_order ASC, t.use_count DESC, t.update_time DESC, t.id DESC LIMIT #{limit}

SELECT

FROM ai_prompt_template
WHERE tenant_id = #{tenantId}
  AND id = #{id}
  AND del_flag = '0'
LIMIT 1

SELECT COUNT(1)
FROM ai_prompt_template
WHERE tenant_id = #{tenantId}
  AND template_code = #{templateCode}
  AND del_flag = '0'

  AND id != #{excludeId}

mapper.update:
UPDATE ai_prompt_template
SET del_flag = '1',
    update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND id = #{id}
  AND del_flag = '0'
